// Gugustus - KillAura.java (autoblock with C07 RELEASE_USE_ITEM)
// Reproduced from actual 1.8.9 client source
@Override
public void onDisable() {
  if (blockMode.getSelected().equals("BlocksMC")
    || blockMode.getSelected().equals("Intave")) {
    // Release blocking before disabling killaura
    mc.thePlayer.sendQueue.addToSendQueueDirect(
      new C07PacketPlayerDigging(
        C07PacketPlayerDigging.Action.RELEASE_USE_ITEM,
        BlockPos.ORIGIN, EnumFacing.DOWN));
  }
}

// During attack loop:
