// Swift Developer Alpha - FastBreak.java
if (event.getPacket() instanceof C07PacketPlayerDigging) {
  C07PacketPlayerDigging packet = (C07PacketPlayerDigging) event.getPacket();
  if (packet.getStatus() == C07PacketPlayerDigging.Action.START_DESTROY_BLOCK) {
    // Modify block break timing
    mc.getNetHandler().addToSendQueue(
      new C07PacketPlayerDigging(C07PacketPlayerDigging.Action.STOP_DESTROY_BLOCK, packet.getPosition(), packet.getFacing()));
  }
